#include <stdio.h>
#include <stdint.h>

// Helper to print unsigned __int128
void print_uint128(__uint128_t x) {
    if (x == 0) { putchar('0'); return; }
    char buf[40]; int i = 0;
    while (x > 0) {
        buf[i++] = '0' + (x % 10);
        x /= 10;
    }
    while (i--) putchar(buf[i]);
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    const __uint128_t AIRPLANES = (__uint128_t)10000000000ULL; // 10^10
    while (T--) {
        unsigned long long X, Y, Z;
        scanf("%llu %llu %llu", &X, &Y, &Z);
        __uint128_t totalSeats = (__uint128_t)X * AIRPLANES;
        __uint128_t sold = totalSeats < Y ? totalSeats : (__uint128_t)Y;
        __uint128_t revenue = sold * Z;
        print_uint128(revenue);
        if (T) putchar('\n');
    }
    return 0;
}

