#include <bits/stdc++.h>
using namespace std;

string toString(__int128 v) {
    if (v == 0) return "0";
    bool neg = v < 0;
    if (neg) v = -v;
    string s;
    while (v > 0) {
        s.push_back('0' + v % 10);
        v /= 10;
    }
    if (neg) s.push_back('-');
    reverse(s.begin(), s.end());
    return s;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    const __int128 AIRPLANES = (__int128)10000000000LL; // 10^10
    while (T--) {
        long long X, Y, Z;
        cin >> X >> Y >> Z;
        __int128 totalSeats = (__int128)X * AIRPLANES;
        __int128 sold = totalSeats < (__int128)Y ? totalSeats : (__int128)Y;
        __int128 revenue = sold * Z;
        cout << toString(revenue);
        if (T) cout << '\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    private static final long AIRPLANES = 10_000_000_000L; // 10^10
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            long X = Long.parseLong(st.nextToken());
            long Y = Long.parseLong(st.nextToken());
            long Z = Long.parseLong(st.nextToken());
            // Use java.math.BigInteger to avoid overflow
            java.math.BigInteger totalSeats = java.math.BigInteger.valueOf(X).multiply(java.math.BigInteger.valueOf(AIRPLANES));
            java.math.BigInteger sold = totalSeats.min(java.math.BigInteger.valueOf(Y));
            java.math.BigInteger revenue = sold.multiply(java.math.BigInteger.valueOf(Z));
            out.append(revenue.toString());
            if (t + 1 < T) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

